SELECT user_id, MAX(access_date) AS most_recent_access
FROM polygon_access_logs
GROUP BY user_id;

SELECT polygon_id
FROM geospatial_polygons
WHERE updated_at > '2023-05-02 00:00:00';

SELECT dataset_name 
FROM polygon_datasets 
WHERE dataset_id = 1;

SELECT description 
FROM geospatial_polygons 
WHERE polygon_id = 1;

SELECT polygon_id, geometry
FROM geospatial_polygons
WHERE category_id = 0 AND created_at > '2023-05-01' AND polygon_id < 5;

SELECT * 
FROM polygon_access_logs
WHERE polygon_id = 1;

SELECT category_id, COUNT(*) as polygon_count
FROM geospatial_polygons
GROUP BY category_id;

SELECT COUNT(DISTINCT user_id)
FROM polygon_access_logs
WHERE access_date = '2023-05-01';
